{
  "name": "project-management",
  "version": "1.0.0",
  "description": "A simple project management application",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "dependencies": {
    "express": "^4.17.3"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };

const { randomUUID } = require('node:crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };

const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'DUPLICATE_PROJECT') {
      sendError(res, 409, 'DUPLICATE_PROJECT', 'Project already exists');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }
  const newProject = { id: generateId(), name };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = { getAllProjects, createProject };

const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  try {
    const tasks = await tasksService.getTasksByProject(projectId);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'TASK_NOT_FOUND') {
      sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let tasksStore = [];

async function getTasksByProject(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = { getTasksByProject, updateTaskStatus };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }
  try {
    const member = await membersService.addMemberToProject(projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let membersStore = [];

async function addMemberToProject(projectId, userId, role) {
  const member = { id: generateId(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = { addMemberToProject };

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Message is required');
  }
  try {
    const comment = await commentsService.addCommentToTask(projectId, taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    if (error.code === 'TASK_NOT_FOUND') {
      sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let commentsStore = [];

async function addCommentToTask(projectId, taskId, message) {
  const comment = { id: generateId(), projectId, taskId, message };
  commentsStore.push(comment);
  return comment;
}

module.exports = { addCommentToTask };
